In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid < 0) {  // Error
        perror("fork");
        return 1;
    } else if (pid == 0) {  // Child process
        // Close the write end of the pipe
        close(pipefd[1]);

        // Redirection: file descriptor 0 (stdin) is now connected to the read end of the pipe
        dup2(pipefd[0], 0);

        // Close the pipe file descriptor
        close(pipefd[0]);

        // Execute a new program
        execlp("/bin/cat", "cat", (char*)nullptr);
        perror("execlp");
        _exit(1);  // Ensure we exit if execlp fails
    } else {  // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Redirection: file descriptor 1 (stdout) is now connected to the write end of the pipe
        dup2(pipefd[1], 1);

        // Close the pipe file descriptor
        close(pipefd[1]);

        // Print to the child process
        fprintf(stdout, "Hello, World!\n");

        // Wait for the child process to terminate
        waitpid(pid, nullptr, 0);

        // Close the pipe (cleanup)
    }

    return 0;
}
```

**Explanation:**
- `pipe(pipefd)` creates a pipe and returns a file descriptor for both reading and writing.
- `fork()` creates a copy of the current process.
- In the child process (`pid == 0`), we close the write end of the pipe and redirect the standard input (`stdin`, file descriptor 0) to the read end of the pipe using `dup2()`.
- We then execute a new program (`cat` in this case) with `execlp()`.

